-- 1. Настройка схемы и часового пояса
CREATE SCHEMA IF NOT EXISTS atgate;
SET search_path TO atgate;

-- Гарантирует, что БД будет отдавать и принимать время в вашем поясе (+3)
SET timezone TO 'Europe/Minsk'; 

-- Функция для автоматического обновления поля updated_at (нужна для триггера)
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = CURRENT_TIMESTAMP;
    RETURN NEW;
END;
$$ language 'plpgsql';

-- 2. Таблица Каналы
CREATE TABLE IF NOT EXISTS "AtGateChannel" (
    channel_id BIGINT PRIMARY KEY,
    channel_name TEXT NOT NULL,
    is_blocked BOOLEAN DEFAULT FALSE,
    registered_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "AtGateChannel" IS 'Каналы, для которых работает бот';
COMMENT ON COLUMN "AtGateChannel".channel_id IS 'Уникальный Telegram ID канала';
COMMENT ON COLUMN "AtGateChannel".channel_name IS 'Произвольное название канала';
COMMENT ON COLUMN "AtGateChannel".is_blocked IS 'Флаг блокировки канала (по умолчанию FALSE)';
COMMENT ON COLUMN "AtGateChannel".registered_at IS 'Дата и время добавления канала';

-- 3. Таблица Администраторы
CREATE TABLE IF NOT EXISTS "AtGateAdmins" (
    user_id BIGINT PRIMARY KEY,
    username TEXT,
    status JSONB DEFAULT '{}',
    is_blocked BOOLEAN DEFAULT TRUE,
    registered_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "AtGateAdmins" IS 'Администраторы с правами управления системой';
COMMENT ON COLUMN "AtGateAdmins".user_id IS 'Уникальный Telegram ID администратора';
COMMENT ON COLUMN "AtGateAdmins".username IS 'Юзернейм администратора в Telegram (без @)';
COMMENT ON COLUMN "AtGateAdmins".status IS 'Текущее состояние админа (JSONB-контекст для сценариев)';
COMMENT ON COLUMN "AtGateAdmins".is_blocked IS 'Флаг блокировки доступа к админ-панели (по умолчанию TRUE)';
COMMENT ON COLUMN "AtGateAdmins".registered_at IS 'Дата и время назначения/регистрации администратора';

-- 4. Таблица Пользователи
CREATE TABLE IF NOT EXISTS "AtGateUser" (
    user_id BIGINT PRIMARY KEY,
    username TEXT,
    first_name TEXT,
    last_name TEXT,
    registered_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "AtGateUser" IS 'Данные пользователей Telegram, запустивших бота';
COMMENT ON COLUMN "AtGateUser".user_id IS 'Уникальный Telegram ID пользователя';
COMMENT ON COLUMN "AtGateUser".username IS 'Юзернейм пользователя в Telegram (без @)';
COMMENT ON COLUMN "AtGateUser".first_name IS 'Имя пользователя';
COMMENT ON COLUMN "AtGateUser".last_name IS 'Фамилия пользователя';
COMMENT ON COLUMN "AtGateUser".registered_at IS 'Дата и время первого входа в бота';

-- 5. Таблица Цели
CREATE TABLE IF NOT EXISTS "AtGateTarget" (
    channel_id BIGINT REFERENCES "AtGateChannel"(channel_id) ON DELETE CASCADE,
    type_target TEXT DEFAULT 'подписка на тг канал',
    parameters JSONB DEFAULT '{}',
    code_word TEXT NOT NULL,
    target_code CHAR(5) PRIMARY KEY, 
    link_target TEXT NOT NULL,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "AtGateTarget" IS 'Связка кодовых слов с подарками и стартовыми кодами бота';
COMMENT ON COLUMN "AtGateTarget".channel_id IS 'ID канала, к которому привязан подарок';
COMMENT ON COLUMN "AtGateTarget".type_target IS 'Тип выполняемой цели (например, подписка на тг канал)';
COMMENT ON COLUMN "AtGateTarget".parameters IS 'Дополнительные параметры цели в формате JSONB';
COMMENT ON COLUMN "AtGateTarget".code_word IS 'Слово-триггер из Инстаграм, которому соответствует этот код';
COMMENT ON COLUMN "AtGateTarget".target_code IS 'Уникальный 5-значный код для ссылки формата t.me/bot?start=XXXXX';
COMMENT ON COLUMN "AtGateTarget".link_target IS 'Ссылка на конкретный пост с подарком внутри канала';
COMMENT ON COLUMN "AtGateTarget".created_at IS 'Дата и время создания цели';

-- 6. Таблица Взаимодействия
CREATE TABLE IF NOT EXISTS "AtGateInteraction" (
    id SERIAL PRIMARY KEY,
    user_id BIGINT REFERENCES "AtGateUser"(user_id) ON DELETE CASCADE,
    invite_link TEXT, 
    target_code CHAR(5) REFERENCES "AtGateTarget"(target_code) ON DELETE RESTRICT, 
    status TEXT, 
    extra JSONB DEFAULT '{}',
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "AtGateInteraction" IS 'Лог сессий и этапов проверки подписок пользователей';
COMMENT ON COLUMN "AtGateInteraction".id IS 'Инкрементный ID записи взаимодействия';
COMMENT ON COLUMN "AtGateInteraction".user_id IS 'ID пользователя, совершившего действие';
COMMENT ON COLUMN "AtGateInteraction".invite_link IS 'Уникальная ссылка-приглашение в канал, выданная этому юзеру для проверки подписки';
COMMENT ON COLUMN "AtGateInteraction".target_code IS 'Код лид-магнита, по которому пользователь изначально пришел';
COMMENT ON COLUMN "AtGateInteraction".status IS 'Текущий статус (например: "выдана ссылка", "подписался", "получил подарок")';
COMMENT ON COLUMN "AtGateInteraction".extra IS 'Любые дополнительные метаданные взаимодействия для n8n';
COMMENT ON COLUMN "AtGateInteraction".created_at IS 'Дата и время создания записи (старта сессии)';
COMMENT ON COLUMN "AtGateInteraction".updated_at IS 'Дата и время последнего обновления записи (меняется триггером)';

-- Создание триггера для автоматического обновления поля updated_at при каждом UPDATE
CREATE TRIGGER update_interaction_modtime
    BEFORE UPDATE ON "AtGateInteraction"
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

-- 7. Индексы для оптимизации поиска и n8n-воркфлоу
CREATE INDEX IF NOT EXISTS idx_interaction_user ON "AtGateInteraction"(user_id);
CREATE INDEX IF NOT EXISTS idx_interaction_extra ON "AtGateInteraction" USING gin (extra);

-- Уникальный частичный индекс: обеспечивает жесткую уникальность ссылок, при этом игнорирует пустые (NULL) значения
CREATE UNIQUE INDEX IF NOT EXISTS idx_interaction_invite_link_unique 
ON "AtGateInteraction"(invite_link) 
WHERE invite_link IS NOT NULL;

